// Snapshot represents an EBS snapshot
type Snapshot struct {
	ID          string
	Type        string
	Description string
	Tags        []*ec2.Tag
	CreatedAt   time.Time
}

// findSnapshots returns a list of EBS snapshots with the specified tag value
func findSnapshots(svc *ec2.EC2, tagKey, tagValue string) ([]*Snapshot, error) {
	params := &ec2.DescribeSnapshotsInput{
		Filters: []*ec2.Filter{
			{
				Name:   aws.String("tag:" + tagKey),
				Values: []*string{aws.String(tagValue)},
			},
		},
	}

	resp, err := svc.DescribeSnapshots(params)
	if err != nil {
		return nil, err
	}

	var snapshots []*Snapshot
	for _, snapshot := range resp.Snapshots {
		snapshots = append(snapshots, &Snapshot{
			ID:          *snapshot.SnapshotId,
			Type:        tagValue,
			Description: *snapshot.Description,
			Tags:        snapshot.Tags,
			CreatedAt:   *snapshot.StartTime,
		})
	}

	return snapshots, nil
}

// deleteSnapshots deletes the specified snapshots
func deleteSnapshots(svc *ec2.EC2, snapshots []*Snapshot) error {
	if len(snapshots) == 0 {
		return nil
	}

	var snapshotIDs []*string
	for _, snapshot := range snapshots {
		snapshotIDs = append(snapshotIDs, aws.String(snapshot.ID))
	}

	_, err := svc.DeleteSnapshots(&ec2.DeleteSnapshotsInput{
		SnapshotIds: snapshotIDs,
	})
	if err != nil {
		return err
	}

	return nil
