To ensure authenticity, you could modify the `addProduct` function to include a digital signature of the product details. Here's an example implementation using the `ecrecover` function to verify the digital signature:
```scss
// SPDX-License-Identifier: MIT

pragma solidity ^0.8.0;

contract InventoryManagement {
    struct Product {
        uint inventory;
        bytes32 signature;
    }

    mapping(string => Product) inventory;

    function addProduct(string memory product, uint quantity, bytes32 signature) public {
        require(quantity > 0, "Quantity must be greater than zero");
        inventory[product] = Product({
            inventory: quantity,
            signature: signature
        });
    }

    function removeProduct(string memory product, uint quantity) public {
        require(inventory[product].inventory >= quantity, "Not enough inventory");
        inventory[product].inventory -= quantity;
    }

    function getInventory(string memory product) public view returns (uint) {
        return inventory[product].inventory;
    }

    function verifySignature(string memory product, uint quantity, bytes32 r, bytes32 s, uint8 v) public view returns (bool) {
        bytes32 message = keccak256(abi.encodePacked(product, quantity));
        address signer = ecrecover(message, v, r, s);
        return signer == msg.sender;
    }
}
```
