Yes, it is possible to manage multiple clients using fork in a TCP server.

The idea is to create a new child process for each new client connection that is accepted. The child process is responsible for handling the communication with the client, while the parent process continues to listen for new connections. By doing this, each child process can handle a client connection independently of the others.

Here's an example of how to modify the previous code to use fork to handle multiple clients:
```c
#include <stdio.h>
#include <stdlib.h>
#include <sys/socket.h>
#include <netinet/in.h>
#include <string.h>
#include <unistd.h>

#define PORT 8080

int main(int argc, char const *argv[])
{
    int server_fd, new_socket, valread;
    struct sockaddr_in address;
    int opt = 1;
    int addrlen = sizeof(address);
    char buffer[1024] = {0};
    char *hello = "Hello from server";

    // Creating socket file descriptor
    if ((server_fd = socket(AF_INET, SOCK_STREAM, 0)) == 0)
    {
        perror("socket failed");
        exit(EXIT_FAILURE);
    }

    // Forcefully attaching socket to the port 8080
    if (setsockopt(server_fd, SOL_SOCKET, SO_REUSEADDR | SO_REUSEPORT, &opt, sizeof(opt)))
    {
        perror("setsockopt");
        exit(EXIT_FAILURE);
    }
    address.sin_family = AF_INET;
    address.sin_addr.s_addr = INADDR_ANY;
    address.sin_port = htons(PORT);

    // Forcefully attaching socket to the port 8080
    if (bind(server_fd, (struct sockaddr *)&address, sizeof(address)) < 0)
    {
        perror("bind failed");
        exit(EXIT_FAILURE);
    }
    if (listen(server_fd, 3) < 0)
    {
        perror("listen");
        exit(EXIT_FAILURE);
    }

    while (1)
    {
        if ((new_socket = accept(server_fd, (struct sockaddr *)&address, (socklen_t*)&addrlen)) < 0)
        {
            perror("accept");
            exit(EXIT_FAILURE);
        }

        // Fork a new process to handle the new client connection
        int pid = fork();
        if (pid == 0)
        {
            // This is the child process

            // Close the server socket in the child process
            close(server_fd);

            // Handle the client communication
            valread = read(new_socket, buffer, 1024);
            printf("Received message from client: %s\n", buffer);
            send(new_socket, hello, strlen(hello), 0);
            printf("Hello message sent to client\n");

            // Close the client socket in the child process
            close(new_socket);

            // Terminate the child process
            exit(0);
        }
        else if (pid < 0)
        {
            perror("fork failed");
            exit(EXIT_FAILURE);
        }

        // This is the parent process

        // Close the client socket in the parent process
        close(new_socket);
    }
    return 0;
}
```
In this modified code, when a new client connection is accepted, a new child process is forked to handle the communication with the client. The parent process continues to listen for new connections. When the child process is finished handling the client communication, it terminates. The parent process closes the client socket and waits for the next client connection.

