Metaprogramming is a technique in which a program can be modified at runtime, by writing code that manipulates the program itself. Here are a few ways to do metaprogramming in JavaScript:

1. Using `eval()`: `eval()` is a function that executes a string as if it were JavaScript code. For example:
```
let x = 10;
let y = 20;
let expression = "x + y";
let result = eval(expression);  // result is 30
```
1. Using the `Function` constructor: The `Function` constructor allows you to create a new function from a string of code. For example:
```
let code = "return x + y";
let func = new Function("x", "y", code);
let result = func(10, 20);  // result is 30
```
1. Using the `new` operator with a constructor function: When you create an object using the `new` operator and a constructor function, the constructor function is executed with the `this` keyword set to the new object. This allows you to add properties and methods to the object at runtime. For example:
```
function MyObject(x, y) {
  this.x = x;
  this.y = y;
  this.sum = function() {
    return this.x + this.y;
  }
}

let obj = new MyObject(10, 20);
console.log(obj.sum());  // prints 30
```
1. Using the `Object.defineProperty()` method: This method allows you to add new properties to an object, or modify the behavior of existing properties. For example:
```
let obj = {};
Object.defineProperty(obj, "x", {
  value: 10,
  writable: true,
  enumerable: true,
  configurable: true
});
console.log(obj.x);  // prints 10
```
1. Using the `Object.defineProperties()` method: This method is similar to `Object.defineProperty()`, but allows you to define multiple properties at once.
2. Using the `Object.create()` method: This method creates a new object with the specified prototype object and properties. For example:
```
let prototype = {
  sayHi: function() {
    console.log("Hi");
  }
};
let obj = Object.create(prototype);
obj.sayHi();  // prints "Hi"
```
1. Using the `Object.setPrototypeOf()` method: This method sets the prototype (i.e., the internal `[[Prototype]]` property) of an object to a specified object or null. For example:
```
let obj = {};
Object.setPrototypeOf(obj, Array.prototype);
console.log(obj instanceof Array);  // prints "true"
```

